/** Build a fresh, validated-ish snapshot (fields required by contracts filled). */
export function buildSampleSnapshot(): SampleSnapshot {
  const generation = 1;
  const confidence = 1;
  const derivation = "extracted" as const;
  const withDefaults = <T extends object>(
    record: T,
    evidenceId: string,
  ): IntelligenceFileRecord | IntelligenceSymbolRecord | IntelligenceRelationshipRecord => ({
    ...record,
    evidenceIds: [evidenceId],
    confidence,
    generation,
  }) as IntelligenceFileRecord | IntelligenceSymbolRecord | IntelligenceRelationshipRecord;

  const snapshot: IntelligenceSnapshot = {
    manifest: {
      schemaVersion: INTELLIGENCE_SCHEMA_VERSION,
      generation,
      scanRevision: 1,
      repositoryId: "repo:1",
      status: "ready",
      createdAt: new Date("2026-07-20T00:00:00Z").toISOString(),
      completedAt: new Date("2026-07-20T00:00:00Z").toISOString(),
      extractorVersions: { typescript: "1", sql: "1", cpg: "1" },
    },
    repository: {
      id: "repo:1",
      displayName: "Sample Orders Repo",
      workspaceRoots: [
        {
          id: "root:1",
          name: "Sample Orders Repo",
          evidenceIds: ["ev:routeController"],
        },
      ],
      branch: "main",
      headCommit: "abc123",
      evidenceIds: ["ev:routeController"],
    },
    files: files.map((file, index) =>
      withDefaults(
        file,
        [
          "ev:routeController",
          "ev:ctrlService",
          "ev:serviceRepo",
          "ev:repoTable",
          "ev:serviceCalls",
          "ev:testCover",
          "ev:configUse",
          "ev:cycle",
          "ev:unresolved",
        ][index] ?? "ev:routeController",
      ),
    ) as unknown as IntelligenceFileRecord[],
    symbols: symbols.map((symbol, index) =>
      withDefaults(
        symbol,
        [
          "ev:routeController",
          "ev:ctrlService",
          "ev:serviceRepo",
          "ev:repoTable",
          "ev:serviceCalls",
          "ev:serviceCalls",
          "ev:repoTable",
          "ev:testCover",
          "ev:testCover",
          "ev:configUse",
          "ev:cycle",
          "ev:cycle",
          "ev:unresolved",
        ][index] ?? "ev:routeController",
      ),
    ) as unknown as IntelligenceSymbolRecord[],
    relationships: relationships.map((rel, index) =>
      withDefaults(
        rel,
        [
          "ev:routeController",
          "ev:ctrlService",
          "ev:serviceRepo",
          "ev:repoTable",
          "ev:serviceConfig" /*reuse a real id*/,
          "ev:testCover",
          "ev:testCover",
          "ev:unresolved",
          "ev:cycle",
          "ev:cycle",
          "ev:extImport" /*reuse*/,
          "ev:routeController",
        ][index] ?? "ev:routeController",
      ),
    ) as unknown as IntelligenceRelationshipRecord[],
    evidence: evidence.map((ev) => ({
      ...ev,
      confidence,
      generation,
    })) as IntelligenceEvidenceRecord[],
    diagnostics: [],
    contributions: [],
    indexes: {
      byName: {},
      byQualifiedName: {},
      byPath: {},
      byType: {},
      byLanguage: {},
      incoming: {},
      outgoing: {},
      routeHandlers: {},
      testTargets: {},
      packageMembership: {},
      configurationUsage: {},
    },
  };

  return {
    snapshot,
    ids: {
      route: "sym:route",
      controllerMethod: "sym:controllerMethod",
      service: "sym:service",
      serviceMethod: "sym:serviceMethod",
      repository: "sym:repo",
      repositoryMethod: "sym:repoMethod",
      table: "sym:table",
      test: "sym:test",
      testCase: "sym:testCase",
      config: "sym:config",
      cycleA: "sym:cycleA",
      cycleB: "sym:cycleB",
      unresolved: "sym:unresolved",
      externalFile: "file:external",
      serviceFile: "file:service",
    },
    evidenceIds: {
      routeController: "ev:routeController",
      ctrlService: "ev:ctrlService",
      serviceRepo: "ev:serviceRepo",
      repoTable: "ev:repoTable",
      serviceCalls: "ev:serviceCalls",
      testCover: "ev:testCover",
      configUse: "ev:configUse",
      cycle: "ev:cycle",
      unresolved: "ev:unresolved",
    },
  };
}
